defmodule UserOnboarding do
  def call(user_id) do
    with {:ok, user} <- Accounts.fetch_user(user_id),
         {:ok, plan} <- Billing.create_trial(user),
         {:ok, _mail} <- Mailer.send_welcome(user) do
      {:ok, %{user: user, plan: plan}}
    else
      {:error, :not_found} -> {:error, "User #{user_id} not found"}
      {:error, :payment_gateway_down} -> {:error, "Retry later"}
      {:error, reason} -> {:error, reason}
    end
  end
end

